{
  "name": "Daily Bike Storage Registration",
  "description": "A premium, minimalist customer registration form for long-term bicycle storage services."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore";

// TODO: Replace these values with your actual Firebase configuration in your .env file
// or paste them directly here if testing locally without env setup.
const firebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

export { db };

export interface StorageRequestData {
  name: string;
  phone: string;
  bikeModel: string;
  durationMonths: number;
  notes: string;
  status: 'pending';
  timestamp: string;
}

export interface FormData {
  name: string;
  phone: string;
  bikeModel: string;
  durationMonths: number;
  notes: string;
}

export enum Step {
  HERO = 0,
  DETAILS = 1,
  BIKE_INFO = 2,
  DURATION = 3,
  SUCCESS = 4
}

import { collection, addDoc } from "firebase/firestore";
import { db } from "../firebaseConfig";
import { StorageRequestData, FormData } from "../types";

const COLLECTION_NAME = "storageRequests";

export const submitStorageRequest = async (formData: FormData): Promise<string> => {
  try {
    const payload: StorageRequestData = {
      ...formData,
      status: 'pending',
      timestamp: new Date().toISOString(),
    };

    const docRef = await addDoc(collection(db, COLLECTION_NAME), payload);
    return docRef.id;
  } catch (error) {
    console.error("Error adding document: ", error);
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  isLoading = false,
  className = '',
  disabled,
  ...props 
}) => {
  const baseStyles = "relative px-6 py-4 rounded-xl font-semibold transition-all duration-300 transform active:scale-95 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-purple-600 hover:bg-purple-500 text-white shadow-lg shadow-purple-600/30 hover:shadow-purple-600/50",
    secondary: "bg-slate-800 hover:bg-slate-700 text-slate-200",
    outline: "border-2 border-slate-700 hover:border-purple-500 text-slate-300 hover:text-white"
  };

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center gap-2">
           <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </span>
      ) : children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  error?: string;
}

export const Input: React.FC<InputProps> = ({ label, error, className = '', ...props }) => {
  return (
    <div className="w-full mb-4">
      <label className="block text-sm font-medium text-slate-400 mb-2 ml-1">
        {label}
      </label>
      <input
        className={`w-full bg-slate-800/50 border ${error ? 'border-red-500 focus:border-red-500' : 'border-slate-700 focus:border-purple-500'} rounded-xl px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-purple-500 transition-colors ${className}`}
        {...props}
      />
      {error && <p className="mt-1 text-xs text-red-400 ml-1">{error}</p>}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ArrowRight, 
  Bike, 
  Calendar, 
  Check, 
  ChevronLeft, 
  Clock, 
  User, 
  ShieldCheck,
  Smartphone,
  PenTool,
  Info
} from 'lucide-react';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { submitStorageRequest } from './services/storageService';
import { Step, FormData } from './types';

// Initial state
const initialData: FormData = {
  name: '',
  phone: '',
  bikeModel: '',
  durationMonths: 1,
  notes: ''
};

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.HERO);
  const [formData, setFormData] = useState<FormData>(initialData);
  const [isTermsOpen, setIsTermsOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [agreedToTerms, setAgreedToTerms] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Helper to calculate end date
  const getEndDate = (months: number) => {
    const date = new Date();
    date.setMonth(date.getMonth() + months);
    return date.toLocaleDateString('en-ID', { 
      day: 'numeric', 
      month: 'long', 
      year: 'numeric' 
    });
  };

  // Scroll to top on step change
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [step]);

  const handleNext = () => {
    // Basic validation
    if (step === Step.DETAILS) {
      if (!formData.name.trim() || !formData.phone.trim()) {
        setError("Please fill in all required fields.");
        return;
      }
    }
    if (step === Step.BIKE_INFO) {
      if (!formData.bikeModel.trim()) {
        setError("Please tell us about your bike.");
        return;
      }
    }

    setError(null);
    setStep(prev => prev + 1);
  };

  const handleBack = () => {
    setError(null);
    setStep(prev => prev - 1);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (error) setError(null);
  };

  const handleSubmit = async () => {
    if (!agreedToTerms) {
      setError("You must agree to the Terms & Conditions.");
      return;
    }

    setIsSubmitting(true);
    try {
      await submitStorageRequest(formData);
      setStep(Step.SUCCESS);
    } catch (err) {
      console.error(err);
      setError("Something went wrong. Please check your internet connection.");
    } finally {
      setIsSubmitting(false);
      setIsTermsOpen(false);
    }
  };

  const resetForm = () => {
    setFormData(initialData);
    setStep(Step.HERO);
    setAgreedToTerms(false);
  };

  // Progress Bar
  const progress = Math.min((step / 3) * 100, 100);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 font-sans selection:bg-purple-500/30">

      {/* Background decoration */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
        <div className="absolute top-[-10%] right-[-10%] w-96 h-96 bg-purple-600/20 rounded-full blur-3xl opacity-50"></div>
        <div className="absolute bottom-[-10%] left-[-10%] w-96 h-96 bg-blue-600/10 rounded-full blur-3xl opacity-30"></div>
      </div>

      <div className="relative z-10 max-w-md mx-auto min-h-screen flex flex-col p-6">

        {/* Header (except on Hero/Success) */}
        {step > Step.HERO && step < Step.SUCCESS && (
          <div className="mb-8 pt-4">
            <div className="flex items-center justify-between mb-4">
              <button 
                onClick={handleBack}
                className="p-2 -ml-2 text-slate-400 hover:text-white transition-colors"
              >
                <ChevronLeft className="w-6 h-6" />
              </button>
              <div className="text-xs font-semibold tracking-widest text-slate-500 uppercase">
                Step {step} of 3
              </div>
              <div className="w-8"></div> {/* Spacer for alignment */}
            </div>
            {/* Progress Bar */}
            <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
              <div 
                className="h-full bg-purple-600 transition-all duration-500 ease-out" 
                style={{ width: `${progress}%` }}
              ></div>
            </div>
          </div>
        )}

        <main className="flex-grow flex flex-col justify-center">

          {/* HERO */}
          {step === Step.HERO && (
            <div className="text-center space-y-8 animate-fade-in-up">
              <div className="flex justify-center mb-6">
                <div className="w-20 h-20 bg-gradient-to-tr from-purple-600 to-indigo-600 rounded-2xl flex items-center justify-center shadow-xl shadow-purple-900/40">
                  <Bike className="w-10 h-10 text-white" />
                </div>
              </div>
              <div>
                <h1 className="text-4xl font-bold tracking-tight mb-3">
                  Daily Bike<br /><span className="text-purple-400">Storage</span>
                </h1>
                <p className="text-slate-400 text-lg leading-relaxed">
                  Secure, climate-controlled storage for your premium bicycles in Jakarta.
                </p>
              </div>
              <div className="pt-8">
                <Button fullWidth onClick={() => setStep(Step.DETAILS)}>
                  Start Registration <ArrowRight className="w-5 h-5 ml-2" />
                </Button>
              </div>
            </div>
          )}

          {/* STEP 1: DETAILS */}
          {step === Step.DETAILS && (
            <div className="space-y-6 animate-fade-in">
              <div className="mb-6">
                <h2 className="text-2xl font-bold mb-2">Who are you?</h2>
                <p className="text-slate-400">We need your contact info for the receipt.</p>
              </div>

              <div className="space-y-4">
                <Input 
                  label="Full Name" 
                  name="name"
                  placeholder="e.g. Budi Santoso"
                  value={formData.name}
                  onChange={handleInputChange}
                  autoFocus
                />
                <Input 
                  label="WhatsApp Number" 
                  name="phone"
                  type="tel"
                  placeholder="e.g. 0812 3456 7890"
                  value={formData.phone}
                  onChange={handleInputChange}
                />
              </div>

              {error && (
                <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm flex items-center gap-2">
                  <Info className="w-4 h-4" /> {error}
                </div>
              )}

              <Button fullWidth onClick={handleNext} className="mt-6">
                Next Step
              </Button>
            </div>
          )}

          {/* STEP 2: BIKE INFO */}
          {step === Step.BIKE_INFO && (
            <div className="space-y-6 animate-fade-in">
              <div className="mb-6">
                <h2 className="text-2xl font-bold mb-2">Your Bicycle</h2>
                <p className="text-slate-400">Tell us what we are storing.</p>
              </div>

              <div className="space-y-4">
                <Input 
                  label="Bike Model & Type" 
                  name="bikeModel"
                  placeholder="e.g. Brompton C Line, Road Bike Specialized"
                  value={formData.bikeModel}
                  onChange={handleInputChange}
                  autoFocus
                />
                <Input 
                  label="Special Notes (Optional)" 
                  name="notes"
                  placeholder="e.g. Scratched left pedal, flat rear tire"
                  value={formData.notes}
                  onChange={handleInputChange}
                />
              </div>

              {error && (
                 <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm flex items-center gap-2">
                  <Info className="w-4 h-4" /> {error}
                </div>
              )}

              <Button fullWidth onClick={handleNext} className="mt-6">
                Next Step
              </Button>
            </div>
          )}

          {/* STEP 3: DURATION */}
          {step === Step.DURATION && (
            <div className="space-y-6 animate-fade-in">
              <div className="mb-4">
                <h2 className="text-2xl font-bold mb-2">How long?</h2>
                <p className="text-slate-400">Select your storage duration.</p>
              </div>

              <div className="bg-slate-800/50 rounded-2xl p-6 border border-slate-700">
                <div className="flex items-center justify-between mb-8">
                  <span className="text-slate-400 font-medium">Duration</span>
                  <span className="text-3xl font-bold text-purple-400">
                    {formData.durationMonths} <span className="text-base text-slate-400 font-normal">Months</span>
                  </span>
                </div>

                <input
                  type="range"
                  min="1"
                  max="12"
                  step="1"
                  value={formData.durationMonths}
                  onChange={(e) => setFormData(prev => ({...prev, durationMonths: parseInt(e.target.value)}))}
                  className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-purple-600 mb-6"
                />

                <div className="grid grid-cols-6 gap-2 mb-6">
                  {[1, 3, 6, 12].map((m) => (
                    <button
                      key={m}
                      onClick={() => setFormData(prev => ({...prev, durationMonths: m}))}
                      className={`col-span-1 py-2 rounded-lg text-xs font-bold transition-all ${
                        formData.durationMonths === m 
                          ? 'bg-purple-600 text-white shadow-lg shadow-purple-600/20' 
                          : 'bg-slate-700 text-slate-400 hover:bg-slate-600'
                      } ${m === 12 ? 'col-span-3' : ''}`}
                    >
                      {m === 12 ? '1 Year' : `${m} Mo`}
                    </button>
                  ))}
                </div>

                <div className="flex items-center gap-3 p-4 bg-slate-900/50 rounded-xl border border-slate-700/50">
                  <div className="p-2 bg-slate-800 rounded-lg">
                    <Calendar className="w-5 h-5 text-purple-400" />
                  </div>
                  <div>
                    <div className="text-xs text-slate-400">Estimated Pick-up</div>
                    <div className="font-semibold text-slate-200">{getEndDate(formData.durationMonths)}</div>
                  </div>
                </div>
              </div>

              {error && (
                 <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm flex items-center gap-2">
                  <Info className="w-4 h-4" /> {error}
                </div>
              )}

              <Button fullWidth onClick={() => setIsTermsOpen(true)} className="mt-4">
                Review & Submit
              </Button>
            </div>
          )}

          {/* SUCCESS */}
          {step === Step.SUCCESS && (
            <div className="text-center animate-fade-in-up">
              <div className="flex justify-center mb-6">
                <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center">
                  <Check className="w-10 h-10 text-green-500" />
                </div>
              </div>
              <h2 className="text-3xl font-bold mb-2">Request Sent!</h2>
              <p className="text-slate-400 mb-8 max-w-xs mx-auto">
                We have received your storage request. Our team will contact you via WhatsApp shortly to confirm the drop-off.
              </p>

              <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700 text-left mb-8 max-w-sm mx-auto">
                <div className="text-xs text-slate-500 uppercase tracking-wider mb-2">Summary</div>
                <div className="flex justify-between mb-1">
                  <span className="text-slate-400">Bike</span>
                  <span className="font-medium text-white">{formData.bikeModel}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-400">Duration</span>
                  <span className="font-medium text-purple-400">{formData.durationMonths} Months</span>
                </div>
              </div>

              <Button variant="secondary" onClick={resetForm}>
                Register Another Bike
              </Button>
            </div>
          )}

        </main>
      </div>

      {/* TERMS MODAL */}
      {isTermsOpen && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div 
            className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm transition-opacity" 
            onClick={() => setIsTermsOpen(false)}
          ></div>
          <div className="relative w-full max-w-md bg-slate-900 rounded-t-2xl sm:rounded-2xl shadow-2xl border border-slate-800 flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-800">
              <h3 className="text-xl font-bold">Terms & Conditions</h3>
            </div>

            <div className="p-6 overflow-y-auto space-y-4 text-sm text-slate-300">
              <p className="flex gap-3">
                <span className="font-bold text-purple-500">1.</span>
                Payment must be settled before bike drop-off.
              </p>
              <p className="flex gap-3">
                <span className="font-bold text-purple-500">2.</span>
                Late pick-ups exceeding 7 days will incur a daily fine of IDR 50,000.
              </p>
              <p className="flex gap-3">
                <span className="font-bold text-purple-500">3.</span>
                Daily Bike Storage is not liable for damages caused by force majeure (flood, earthquake, etc.).
              </p>
              <p className="flex gap-3">
                <span className="font-bold text-purple-500">4.</span>
                Bikes not claimed within 3 months after end date may be auctioned to cover costs.
              </p>
            </div>

            <div className="p-6 border-t border-slate-800 bg-slate-900 rounded-b-2xl">
              <label className="flex items-center gap-3 mb-6 cursor-pointer group">
                <div className={`w-6 h-6 rounded border flex items-center justify-center transition-colors ${agreedToTerms ? 'bg-purple-600 border-purple-600' : 'border-slate-600 group-hover:border-purple-500'}`}>
                  {agreedToTerms && <Check className="w-4 h-4 text-white" />}
                </div>
                <input 
                  type="checkbox" 
                  className="hidden" 
                  checked={agreedToTerms} 
                  onChange={(e) => setAgreedToTerms(e.target.checked)} 
                />
                <span className="text-slate-300 group-hover:text-white transition-colors">I agree to the Terms & Conditions</span>
              </label>

              <div className="flex gap-3">
                <Button variant="secondary" fullWidth onClick={() => setIsTermsOpen(false)}>
                  Cancel
                </Button>
                <Button fullWidth onClick={handleSubmit} disabled={!agreedToTerms} isLoading={isSubmitting}>
                  Confirm Request
                </Button>
              </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

