export interface StorageRequestData {
  name: string;
  phone: string;
  bikeModel: string;
  startDate: string;
  endDate: string;
  notes: string;
  duration: string;
  status: 'pending';
  timestamp: string;
}

export interface FormData {
  name: string;
  phone: string;
  bikeModel: string;
  startDate: string;
  endDate: string;
  notes: string;
}

export enum Step {
  HERO = 0,
  DETAILS = 1,
  BIKE_INFO = 2,
  DURATION = 3,
  SUCCESS = 4
}

import { collection, addDoc } from "firebase/firestore";
import { db } from "../firebaseConfig";
import { StorageRequestData, FormData } from "../types";

const COLLECTION_NAME = "storageRequests";

export const submitStorageRequest = async (formData: FormData, duration: string): Promise<string> => {
  try {
    const payload: StorageRequestData = {
      ...formData,
      duration,
      status: 'pending',
      timestamp: new Date().toISOString(),
    };

    const docRef = await addDoc(collection(db, COLLECTION_NAME), payload);
    return docRef.id;
  } catch (error) {
    console.error("Error adding document: ", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  ArrowRight, 
  Bike, 
  Calendar, 
  Check, 
  ChevronLeft, 
  Info,
  Clock
} from 'lucide-react';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { submitStorageRequest } from './services/storageService';
import { Step, FormData } from './types';

// Initial state
const initialData: FormData = {
  name: '',
  phone: '',
  bikeModel: '',
  startDate: '',
  endDate: '',
  notes: ''
};

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.HERO);
  const [formData, setFormData] = useState<FormData>(initialData);
  const [isTermsOpen, setIsTermsOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [agreedToTerms, setAgreedToTerms] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Helper to format date for display
  const formatDate = (dateString: string) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('id-ID', { 
      day: 'numeric', 
      month: 'long', 
      year: 'numeric' 
    });
  };

  // Helper to calculate duration
  const getDurationString = (start: string, end: string) => {
    if (!start || !end) return null;
    const startDate = new Date(start);
    const endDate = new Date(end);

    // Allow same day, but not past date
    if (endDate < startDate) return null;

    const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

    if (diffDays === 0) return "1 Hari"; // Minimum 1 day
    if (diffDays < 30) {
      return `${diffDays} Hari`;
    }

    const months = Math.floor(diffDays / 30);
    const days = diffDays % 30;

    if (days === 0) return `${months} Bulan`;
    return `${months} Bulan ${days} Hari`;
  };

  // Scroll to top on step change
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [step]);

  const handleNext = () => {
    // Basic validation
    if (step === Step.DETAILS) {
      if (!formData.name.trim() || !formData.phone.trim()) {
        setError("Mohon isi semua data yang wajib.");
        return;
      }
    }
    if (step === Step.BIKE_INFO) {
      if (!formData.bikeModel.trim()) {
        setError("Mohon informasikan tentang sepeda Anda.");
        return;
      }
    }

    setError(null);
    setStep(prev => prev + 1);
  };

  const handleBack = () => {
    setError(null);
    setStep(prev => prev - 1);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    if (name === 'phone') {
      // Allow only numbers and '+'
      if (value && !/^[0-9+]+$/.test(value)) {
        return; 
      }
    }

    setFormData(prev => ({ ...prev, [name]: value }));
    if (error) setError(null);
  };

  const handleDateSubmit = () => {
    if (!formData.startDate || !formData.endDate) {
      setError("Mohon pilih tanggal mulai dan selesai.");
      return;
    }

    if (new Date(formData.endDate) < new Date(formData.startDate)) {
      setError("Tanggal selesai harus setelah tanggal mulai.");
      return;
    }

    setError(null);
    setIsTermsOpen(true);
  };

  const handleSubmit = async () => {
    if (!agreedToTerms) {
      setError("Anda harus menyetujui Syarat & Ketentuan.");
      return;
    }

    setIsSubmitting(true);
    try {
      const duration = getDurationString(formData.startDate, formData.endDate) || "Unknown";
      await submitStorageRequest(formData, duration);
      setStep(Step.SUCCESS);
    } catch (err) {
      console.error(err);
      setError("Terjadi kesalahan. Mohon periksa koneksi internet Anda.");
